// T614 MilestoneContractManager — immutability gate + sum validation
const CONTRACT_IMMUTABLE_FIELDS = ['clientId', 'contractTotal', 'gigId', 'freelancerId'] as const;

async updateContract(contractId: string, updates: Record<string, unknown>): Promise<DataProcessResult<Record<string, unknown>>> {
  // ORDER 1: compile-time immutability check
  const fieldsToUpdate = Object.keys(updates);
  const immutableAttempt = fieldsToUpdate.filter(f =>
    (CONTRACT_IMMUTABLE_FIELDS as readonly string[]).includes(f)
  );
  if (immutableAttempt.length > 0) {
    await this.queue.enqueue('ContractFieldImmutable', { contractId, field: immutableAttempt[0] });
    return DataProcessResult.failure('FIELD_IMMUTABLE', `Field ${immutableAttempt[0]} cannot be modified`);
  }

  // ORDER 2: milestone sum validation
  const contract = (await this.db.searchDocuments('contracts', { contractId })).data[0];
  const milestones = (updates['milestones'] ?? contract['milestones']) as Array<Record<string, unknown>>;
  const sum = milestones.reduce((acc, m) => acc + Number(m['amount']), 0);
  if (sum !== Number(contract['contractTotal'])) {
    await this.queue.enqueue('MilestoneSumMismatch', { contractId, expected: contract['contractTotal'], actual: sum });
    return DataProcessResult.failure('MILESTONE_SUM_MISMATCH', ...);
  }

  // ORDER 3: OCC write
  const writeResult = await this.db.storeDocument('contracts', { contractId, ...updates, version: contract['version'] });
  if (writeResult.data?.['conflict']) {
    await this.queue.enqueue('ContractUpdateConflict', { contractId });
    return DataProcessResult.failure('OCC_CONFLICT', 'Contract was modified concurrently');
  }

  // DNA-8: audit BEFORE enqueue
  await this.db.storeDocument('contract-audit', { contractId, action: 'CONTRACT_UPDATED' });
  await this.queue.enqueue('FreelancerContractActivated', { contractId });
  return DataProcessResult.success({ contractId });
}
